const PROJECT_ID = $json.projectId || 'mwwvwgiw';
// --- Helpers ---
const uid = () =>
  (Math.random().toString(36).slice(2, 10) + Date.now().toString(36)).slice(0, 12);

const makeSlug = (s) => ({
  _type: 'slug',
  current: String(s || '')
    .toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9\-]/g, '')
    .slice(0, 96),
});

function extractJsonString(str) {
  if (typeof str !== 'string') return null;
  const mJson = str.match(/```json\s*([\s\S]*?)```/i);
  if (mJson) return mJson[1].trim();
  const mCode = str.match(/```+\s*([\s\S]*?)```+/);
  if (mCode) return mCode[1].trim();
  const start = str.indexOf('{');
  const end = str.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) return str.slice(start, end + 1);
  return null;
}

function safeParseJson(maybe) {
  if (!maybe) return null;
  if (typeof maybe === 'object') return maybe;
  const s = extractJsonString(String(maybe)) ?? String(maybe);
  try { return JSON.parse(s); } catch { return null; }
}

function normalizeBody(body = []) {
  if (typeof body === 'string') {
        const stripInline = (s) => String(s)
          .replace(/\*\*(.+?)\*\*/g, '$1')
          .replace(/\*(.+?)\*/g, '$1')
          .replace(/__(.+?)__/g, '$1')
          .replace(/`(.+?)`/g, '$1')
          .trim();
        const lines = body.split(/\r?\n/);
        const blocks = [];
        let para = [];
        const flushPara = () => {
                if (!para.length) return;
                const text = stripInline(para.join(' '));
                if (text) blocks.push({ _type: 'block', style: 'normal', _key: uid(), markDefs: [], children: [{ _type: 'span', text, marks: [], _key: uid() }] });
                para = [];
        };
        for (const raw of lines) {
                const line = raw.trim();
                if (!line) { flushPara(); continue; }
                const h = line.match(/^(#{1,4})\s+(.*)$/);
                if (h) {
                          flushPara();
                          const style = 'h' + h[1].length;
                          blocks.push({ _type: 'block', style, _key: uid(), markDefs: [], children: [{ _type: 'span', text: stripInline(h[2]), marks: [], _key: uid() }] });
                          continue;
                }
                const li = line.match(/^[-*]\s+(.*)$/);
                if (li) {
                          flushPara();
                          blocks.push({ _type: 'block', style: 'normal', listItem: 'bullet', level: 1, _key: uid(), markDefs: [], children: [{ _type: 'span', text: stripInline(li[1]), marks: [], _key: uid() }] });
                          continue;
                }
                para.push(line);
        }
        flushPara();
        body = blocks;
  }
  if (!Array.isArray(body)) body = [];
  return body.map((block) => {
    const b = { ...block };
    b._type = b._type || 'block';
    b._key = b._key || uid();
    b.style = b.style || 'normal';
    b.markDefs = Array.isArray(b.markDefs) ? b.markDefs : [];
    if (Array.isArray(b.children) && b.children.length) {
      b.children = b.children.map((ch) => ({
        _type: 'span',
        text: ch?.text ?? '',
        marks: Array.isArray(ch?.marks) ? ch.marks : [],
        _key: ch?._key || uid(),
      }));
    } else {
      b.children = [{ _type: 'span', text: '', marks: [], _key: uid() }];
    }
    return b;
  });
}

const ref = (id) => ({ _type: 'reference', _ref: id, _key: uid() });
const toSlug = (x) => String(x || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9\-]/g, '').slice(0,96);

// --- Mapping deterministik ---
const AUTHOR_IDS = { 'ai-team': 'author.ai-team' };
const CATEGORY_IDS = {
  'seo': 'ad9fe04f-2573-418c-b2de-837cd86698a7',
  'crm': 'bfc9646f-ab6f-4ece-9bd4-43584b512d58',
  'crm-management': 'bfc9646f-ab6f-4ece-9bd4-43584b512d58',
  'social-media': 'c435c8c0-6f71-46df-84f2-3acbb1434d20',
  'sosial-media': 'c435c8c0-6f71-46df-84f2-3acbb1434d20',
  'marketing': 'cc3fa785-da7e-46da-8c98-1d2befde9090',
};

// Keyword -> slug untuk auto-klasifikasi
const CATEGORY_KEYWORDS = [
  { slug: 'seo', patterns: [/\bseo\b/i, /search engine optimization/i, /optimasi mesin pencari/i] },
  { slug: 'crm', patterns: [/\bcrm\b/i, /customer relationship management/i, /manajemen hubungan pelanggan/i] },
  { slug: 'social-media', patterns: [/\bsocial media\b/i, /\bsosial media\b/i, /\bmedsos\b/i, /media sosial/i] },
  { slug: 'marketing', patterns: [/\bmarketing\b/i, /\bpemasaran\b/i] },
];

// --- Ambil kandidat payload dari node sebelumnya ---
// Map inputs from modular parent workflow
let inItem = $json.article || $json;
if (inItem && !inItem.body && inItem.bodyMarkdown) {
  inItem.body = inItem.bodyMarkdown;
}


// --- Opsi 2: parse JSON string dari output AI Agent (parser dilepas) ---
(function(){
  try {
    var cands=[inItem, inItem && inItem.output, inItem && inItem.response, inItem && inItem.text, inItem && inItem.json];
    for (var k=0;k<cands.length;k++){
      var s=cands[k];
      if (typeof s==="string" && s.indexOf("{")>=0){
        var t=s.replace(/```json/gi,"").replace(/```/g,"").trim();
        var a=t.indexOf("{"); var b=t.lastIndexOf("}");
        if (a>=0 && b>a){
          var parsed=JSON.parse(t.slice(a,b+1));
          if (parsed && (parsed.title||parsed.body||parsed.slug)){ inItem=parsed; break; }
          if (parsed && parsed.output && (parsed.output.title||parsed.output.body)){ inItem=parsed.output; break; }
        }
      }
    }
  } catch(e){ /* biarkan fallback kandidat di bawah menangani */ }
})();

let ai = null;
if (Array.isArray(inItem) && inItem.length) {
  for (const entry of inItem) {
    const parsed = safeParseJson(entry?.output ?? entry);
    if (parsed && (parsed.title || parsed.body || parsed.slug)) { ai = parsed; break; }
  }
} else {
  const candidates = [inItem, inItem.output, inItem.result, inItem.response?.text, inItem.response, inItem.data, inItem.text, inItem.ai];
  for (const c of candidates) {
    const parsed = safeParseJson(c);
    if (parsed && (parsed.title || parsed.body || parsed.slug)) { ai = parsed; break; }
  }
}
if (!ai && typeof inItem === 'object' && (inItem.title || inItem.body)) ai = inItem;

// --- Build fields ---
const rawTitle = (ai && typeof ai.title === 'string') ? ai.title.trim() : '';
const body = normalizeBody(ai?.body || []);
const bodyHasContent = Array.isArray(body) && body.length > 0;
if (!rawTitle || /^untitled$/i.test(rawTitle) || !bodyHasContent) {
  throw new Error('Artikel tidak valid: title kosong/Untitled atau body kosong (kemungkinan AI Agent gagal). Publish dibatalkan.');
}
const title = rawTitle;
const slugObj = (ai?.slug && typeof ai.slug === 'object') ? ai.slug : makeSlug(ai?.slug || title);

// excerpt
function plainText(blocks = []) {
  return blocks
    .filter(b => b?._type === 'block')
    .map(b => (Array.isArray(b.children) ? b.children.map(c => c?.text || '').join('') : ''))
    .join('\n')
    .trim();
}
const excerpt = (typeof ai?.excerpt === 'string' && ai.excerpt.trim()) || plainText(body).slice(0, 160);

// author
const authorId = ai?.authorId || (ai?.authorSlug && AUTHOR_IDS[ai.authorSlug]) || AUTHOR_IDS['ai-team'];

// categories: AI + auto-klasifikasi keyword
const categorySlugsFromAi = Array.isArray(ai?.categories) ? ai.categories.map(toSlug) : [];
const fullText = (title + ' ' + plainText(body) + ' ' + (excerpt || '')).toLowerCase();
const categorySlugsAuto = CATEGORY_KEYWORDS
  .filter(({ patterns }) => patterns.some(p => p.test(fullText)))
  .map(x => x.slug);
const allCategorySlugs = Array.from(new Set([...categorySlugsFromAi, ...categorySlugsAuto]));
const categoryIds = allCategorySlugs.map(s => CATEGORY_IDS[s]).filter(Boolean);
const categoryIdsUnique = Array.from(new Set(categoryIds));

// --- Dokumen post ---
const draftDocId = 'drafts.post-' + uid();
const doc = {
  _id: draftDocId,
  _type: 'post',
  title,
  slug: slugObj,
  body,
  excerpt,
  author: authorId ? ref(authorId) : undefined,
  categories: categoryIdsUnique.map(id => ref(id)),
  publishedAt: ai?.publishedAt || new Date().toISOString(),
};

// --- Pastikan author taxonomy ada (idempotent) ---
const taxonomyMutations = [];
if (authorId === 'author.ai-team') {
  taxonomyMutations.push({
    createIfNotExists: {
      _id: 'author.ai-team',
      _type: 'author',
      name: 'AI Team',
      slug: { _type: 'slug', current: 'ai-team' },
    }
  });
}

const _debug = {
  pickedFrom: ai ? 'parsed' : 'fallback',
  hasTitle: Boolean(ai?.title),
  hasBody: Array.isArray(ai?.body) && ai.body.length > 0,
  authorId,
  categorySlugsFromAi,
  categorySlugsAuto,
  allCategorySlugs,
  categoryIds: categoryIdsUnique,
};

return [{
  json: {
    clientName: $json.clientName || "Supermat Client",
    telegramChatId: $json.telegramChatId || "",
    cmsType: "sanity",
    draftDocId,
    draftEditUrl: `https://${PROJECT_ID}.sanity.studio/desk/post;${draftDocId}`,
    mutations: [
      ...taxonomyMutations,
      { createOrReplace: doc },
    ],
    _debug,
  },
}];

// Bisa dapet dari doc atau dari top-level
const docId = $json.docId;
const doc   = $json.doc ?? $json;

const title = doc?.title || 'Untitled';
const slug  = doc?.slug?.current || doc?.slug || 'untitled';
const textBlocks = (doc?.body || []).filter(b => b?._type === 'block');
const firstPara = (textBlocks.find(b => b.style === 'normal')?.children?.[0]?.text || '').slice(0, 220);
const keywords = (doc?.keywords || [])
  .filter(k => typeof k === 'string')
  .slice(0, 6);

const primary = doc?.primaryKeyword || keywords[0] || title;

const baseStyle = 'clean, modern, high detail, blog hero image, negative space for overlay, no text, no watermark';

const prompts = [
  `High-quality blog hero image about "${primary}". ${baseStyle}. Visual focus: concept overview, center composition.`,
  `Supporting illustration for article "${title}". Focus on a concrete sub-aspect: key mechanism or example. ${baseStyle}. Different angle from hero.`,
  `Second supporting visual for "${title}". Complementary perspective (macro or contextual scene). ${baseStyle}.`
];

return prompts.map((prompt, idx) => ({ json: { docId, title, slug, keywords, prompt, idx, totalImages: prompts.length } }));

const out = [];
const allItems = $input.all();
for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];
  const binary = item.binary || {};

  // Get matching JSON from Convert Prompt by index
  let promptJson = {};
  try {
    promptJson = $('Convert Prompt').all()[i].json;
  } catch (e) {
    // Fallback or ignore
  }

  // Merge promptJson into the item's JSON (preserving slug, idx, docId, etc.)
  const mergedJson = Object.assign({}, promptJson, item.json);

  if (binary.data) {
    const bin = binary.data;
    try {
      // Try to parse it as JSON
      const rawString = Buffer.from(bin.data, 'base64').toString('utf-8').trim();
      if (rawString.startsWith('{') && rawString.endsWith('}')) {
        const parsed = JSON.parse(rawString);
        const imgB64 = parsed.result?.image || parsed.image || parsed.img || '';
        if (imgB64) {
          const buf = Buffer.from(imgB64, 'base64');
          out.push({
            json: mergedJson,
            binary: {
              data: {
                data: buf.toString('base64'),
                mimeType: 'image/png',
                fileExtension: 'png',
                fileName: 'image.png'
              }
            }
          });
          continue;
        }
      }
    } catch (e) {
      // Not a valid JSON or parsing failed, fall back
    }
  }

  // Pass through with merged JSON if it's already raw binary
  out.push({
    json: mergedJson,
    binary: binary
  });
}
return out;

const res = $json;
const created = (res.results || []).find(r => r.operation === 'create');
const updated = (res.results || []).find(r => r.operation === 'update');

const picked = created || updated; // prioritas create
return [{
  json: {
    docId: picked?.id,
    doc: picked?.document || null
  }
}];

return items.map(it => {
  const idx = Number(it.json.idx);
  const docId = it.json.docId;
  const assetId = it.json.assetId;
  const k = () => Math.random().toString(36).slice(2,10);
  const imgRef = { _type: 'image', asset: { _type: 'reference', _ref: assetId } };
  const imgBlock = { _type: 'image', _key: k(), asset: { _type: 'reference', _ref: assetId } };
  const para = (t) => ({ _type: 'block', _key: k(), style: 'normal', markDefs: [], children: [{ _type: 'span', _key: k(), text: t || '', marks: [] }] });
  let patches;
  if (idx === 0) {
    patches = [{ set: { mainImage: imgRef } }];
  } else if (idx === 1) {
    patches = [{ insert: { after: 'body[0]', items: [imgBlock, para('')] } }];
  } else {
    patches = [{ insert: { after: 'body[-1]', items: [para(''), para(''), imgBlock] } }];
  }
  const mutationBody = { mutations: patches.map(p => ({ patch: Object.assign({ id: docId }, p) })) };
  return { json: { docId, idx, assetId, patches, mutationBody } };
});

