const SANITY_TOKEN = $('Execute Workflow Trigger').first().json.authToken || 'skBXK0a9JwOX4s9YEv0GMfd995SQhzuCL4zgfWW17YfkvXgjd2xdSoYXQZUsvnyghPgqnzgSciyxYYWqj9TCFYjAfJ9c1XSkcoD2mU4JoPe2ITXuyWQf0qYPdspSCZfAYoH9iJedBa2fRJPg2dWTYT6t1LNZMzPVi7uivlUZ1Kodu7Me1SRk'; // same token as in Publishing Sanity
const GEMINI_API_KEY = 'AIzaSyBbMHPlk1KrdLywqCxr2r5h1GtytRpjzBY';
