const LINK_PREFIX = '/article/'; // change to "/blog/" if posts live under /blog/
const MAX_LINKS = 4 // max internal links to insert per article
const MAX_CANDIDATES = 30; // how many old posts to send to the AI

const uid = () => (Math.random().toString(36).slice(2, 10) + Date.now().toString(36)).slice(0, 12);
