// --- Sanity request helper (uses n8n built-in httpRequest) ---
async function sanity(method, path, body) {
    const opt = {
          method,
          url: `https://${PROJECT_ID}.api.sanity.io/${API_VERSION}/${path}`,
          headers: { Authorization: `Bearer ${SANITY_TOKEN}` },
          json: true,
    };
    if (body) { opt.body = body; opt.headers['Content-Type'] = 'application/json'; }
    return await this.helpers.httpRequest(opt);
}

// --- Gemini request helper ---
async function askGemini(prompt) {
    const url = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${GEMINI_API_KEY}`;
    const res = await this.helpers.httpRequest({
          method: 'POST',
          url,
          headers: { 'Content-Type': 'application/json' },
          json: true,
          body: {
                  contents: [{ parts: [{ text: prompt }] }],
                  generationConfig: { temperature: 0.2, responseMimeType: 'application/json' },
          },
    });
    const text = res?.candidates?.[0]?.content?.parts?.[0]?.text || '';
    return text;
}

// --- 1. Get the freshly-created article ---
const input = $input.first().json;
const docId = input.docId;
const doc = input.doc || {};
let body = Array.isArray(doc.body) ? JSON.parse(JSON.stringify(doc.body)) : [];
const thisTitle = doc.title || '';
if (!docId || body.length === 0) {
    return [{ json: { skipped: true, reason: 'No docId or empty body', docId } }];
}

// --- 2. Fetch all OTHER posts (title + slug + excerpt) as link candidates ---
const groq = `*[_type == "post" && _id != $id && defined(slug.current)]{ "title": title, "slug": slug.current, "excerpt": coalesce(excerpt, "") }[0...${MAX_CANDIDATES}]`;
const qPath = `data/query/${DATASET}?query=${encodeURIComponent(groq)}&$id=${encodeURIComponent(JSON.stringify(docId))}`;
const res = await sanity('GET', qPath);
const candidates = (res.result || []).filter(p => p.title && p.slug);
if (candidates.length === 0) {
    return [{ json: { docId, linksAdded: 0, message: 'No candidate posts found' } }];
}

// --- 3. Build plain text of the article body (with block index) ---
const blockText = [];
body.forEach((block, bi) => {
    if (block && block._type === 'block' && Array.isArray(block.children)) {
          const t = block.children.filter(c => c._type === 'span').map(c => c.text || '').join('');
          if (t.trim()) blockText.push({ bi, text: t });
    }
});

// --- 4. Ask Gemini to pick semantically related posts + anchor phrases ---
const candList = candidates.map((c, i) => `${i}. title: "${c.title}" | slug: ${c.slug}${c.excerpt ? ' | excerpt: ' + c.excerpt.slice(0, 160) : ''}`).join('\n');
const articleText = blockText.map(b => `[block ${b.bi}] ${b.text}`).join('\n');
const prompt = `You are an SEO internal-linking assistant. Given a NEW article and a list of OTHER existing articles, choose up to ${MAX_LINKS} internal links to insert into the new article.\n\nRULES:\n- Pick links based on TOPIC/SEMANTIC relevance, NOT on title matching.\n- The "anchor" MUST be an exact substring (verbatim, case included) that already appears in the new article body text below. Prefer a natural noun phrase of 2-6 words.\n- Each target slug used at most once. Do not link a phrase to an unrelated article.\n- If nothing is relevant, return an empty array.\n- Return ONLY valid JSON: an array of objects {"anchor": string, "slug": string, "reason": string}.\n\nNEW ARTICLE TITLE: "${thisTitle}"\n\nNEW ARTICLE BODY:\n${articleText}\n\nEXISTING ARTICLES (candidates):\n${candList}`;

let picks = [];
try {
    const raw = await askGemini(prompt);
    const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
    picks = JSON.parse(cleaned);
    if (!Array.isArray(picks)) picks = [];
} catch (e) {
    return [{ json: { docId, linksAdded: 0, message: 'Gemini parse error: ' + e.message } }];
}

// --- 5. Inject links into the body based on AI picks ---
const validSlugs = new Set(candidates.map(c => c.slug));
const usedSlugs = new Set();
let linksAdded = 0;

for (const pick of picks) {
    if (linksAdded >= MAX_LINKS) break;
    const anchor = (pick && pick.anchor || '').trim();
    const slug = (pick && pick.slug || '').trim();
    if (!anchor || !slug || !validSlugs.has(slug) || usedSlugs.has(slug)) continue;

    let injected = false;
    for (const block of body) {
          if (injected) break;
          if (!block || block._type !== 'block' || !Array.isArray(block.children)) continue;
          if (!Array.isArray(block.markDefs)) block.markDefs = [];

          for (let ci = 0; ci < block.children.length; ci++) {
                  const span = block.children[ci];
                  if (!span || span._type !== 'span' || typeof span.text !== 'string') continue;
                  if (Array.isArray(span.marks) && span.marks.length) continue; // skip already-marked spans
                  const idx = span.text.indexOf(anchor);
                  if (idx === -1) continue;

                  const before = span.text.slice(0, idx);
                  const middle = span.text.slice(idx, idx + anchor.length);
                  const after = span.text.slice(idx + anchor.length);

                  const markKey = uid();
                  block.markDefs.push({ _key: markKey, _type: 'link', href: LINK_PREFIX + slug });

                  const newSpans = [];
                  if (before) newSpans.push({ _type: 'span', _key: uid(), text: before, marks: [] });
                  newSpans.push({ _type: 'span', _key: uid(), text: middle, marks: [markKey] });
                  if (after) newSpans.push({ _type: 'span', _key: uid(), text: after, marks: [] });

                  block.children.splice(ci, 1, ...newSpans);
                  usedSlugs.add(slug);
                  linksAdded++;
                  injected = true;
                  break;
          }
    }
}

// --- 6. Patch the document with the updated body ---
if (linksAdded === 0) {
    return [{ json: { docId, linksAdded: 0, message: 'AI found no insertable anchors in body', picks } }];
}

const mutations = { mutations: [{ patch: { id: docId, set: { body } } }] };
const patchRes = await sanity('POST', `data/mutate/${DATASET}?returnIds=true`, mutations);

return [{ json: { docId, linksAdded, linkedSlugs: Array.from(usedSlugs), picks, sanityResult: patchRes } }];

