function hostAllowed(u) {
  try {
    if (!/^https:\/\//i.test(u)) return false;
    const h = new URL(u).hostname.toLowerCase();
    return ALLOWED_DOMAINS.some(d => d.charAt(0) === '.' ? h.endsWith(d) : (h === d || h.endsWith('.' + d)));
  } catch (e) { return false; }
}

// --- 1. Get docId from previous node, then RE-FETCH the fresh body (internal links already applied) ---
const input = $input.first().json;
const docId = input.docId;
if (!docId) { return [{ json: { skipped: true, reason: 'No docId from previous node' } }]; }

const groq = '*[_id == $id][0]{title, body}';
const qPath = `data/query/${DATASET}?query=${encodeURIComponent(groq)}&$id=${encodeURIComponent(JSON.stringify(docId))}`;
const fetched = await sanity('GET', qPath);
const doc = (fetched && fetched.result) || {};
let body = Array.isArray(doc.body) ? JSON.parse(JSON.stringify(doc.body)) : [];
const thisTitle = doc.title || '';
if (!body.length) { return [{ json: { skipped: true, reason: 'Empty body', docId } }]; }

// --- 2. Build plain text of the article body (with block index) ---
const blockText = [];
body.forEach((block, bi) => {
  if (block && block._type === 'block' && Array.isArray(block.children)) {
    const t = block.children.filter(c => c._type === 'span').map(c => c.text || '').join('');
    if (t.trim()) blockText.push({ bi, text: t });
  }
});
const articleText = blockText.map(b => `[block ${b.bi}] ${b.text}`).join('\n');

// --- 3. Ask Gemini for external links to authoritative high-DA sources ---
const allowedList = ALLOWED_DOMAINS.join(', ');
const prompt = [
  'You are an SEO assistant adding EXTERNAL outbound links to authoritative, high Domain Authority sources.',
  'RULES:',
  '- "anchor" MUST be an exact substring (verbatim, case included) that already appears in the article body text below. Prefer a natural noun phrase of 2-6 words.',
  '- "url" MUST be a full https:// URL whose domain is one of these ALLOWED high-DA domains ONLY: ' + allowedList,
  '- Choose URLs that genuinely exist and are topically relevant (e.g. the matching Wikipedia article, an official organization page, or a reputable publication). Do NOT invent fake or guessed URLs.',
  '- Insert at most ' + MAX_EXT_LINKS + ' links. Each anchor used at most once. Do not link the same domain twice.',
  '- If nothing relevant and authoritative is available, return an empty array.',
  '- Return ONLY valid JSON: an array of objects {"anchor": string, "url": string, "reason": string}.',
  '',
  'ARTICLE TITLE: "' + thisTitle + '"',
  '',
  'ARTICLE BODY:',
  articleText
].join('\n');

let picks = [];
try {
  const raw = await askGemini(prompt);
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  picks = JSON.parse(cleaned);
  if (!Array.isArray(picks)) picks = [];
} catch (e) { picks = []; }

// --- 4. Insert external links into body as Portable Text marks ---
let linksAdded = 0;
const usedAnchors = new Set();
const usedHosts = new Set();

for (const pick of picks) {
  if (linksAdded >= MAX_EXT_LINKS) break;
  const anchor = (pick && pick.anchor || '').trim();
  const url = (pick && pick.url || '').trim();
  if (!anchor || !url || !hostAllowed(url)) continue;
  let host;
  try { host = new URL(url).hostname.toLowerCase().replace(/^www\./, ''); } catch (e) { continue; }
  if (usedAnchors.has(norm(anchor)) || usedHosts.has(host)) continue;

  let injected = false;
  for (const block of body) {
    if (injected) break;
    if (!block || block._type !== 'block' || !Array.isArray(block.children)) continue;
    if (!Array.isArray(block.markDefs)) block.markDefs = [];
    for (let ci = 0; ci < block.children.length; ci++) {
      const child = block.children[ci];
      if (!child || child._type !== 'span' || typeof child.text !== 'string') continue;
      const idx = child.text.indexOf(anchor);
      if (idx === -1) continue;
      const before = child.text.slice(0, idx);
      const middle = child.text.slice(idx, idx + anchor.length);
      const after = child.text.slice(idx + anchor.length);
      const markKey = uid();
      // External link mark: full URL href, opens in new tab (blank), dofollow + noopener
      block.markDefs.push({ _key: markKey, _type: 'link', href: url, blank: true, rel: 'noopener' });
      const baseMarks = Array.isArray(child.marks) ? child.marks.filter(m => m !== markKey) : [];
      const newSpans = [];
      if (before) newSpans.push({ _type: 'span', _key: uid(), text: before, marks: baseMarks });
      newSpans.push({ _type: 'span', _key: uid(), text: middle, marks: baseMarks.concat([markKey]) });
      if (after) newSpans.push({ _type: 'span', _key: uid(), text: after, marks: baseMarks });
      block.children.splice(ci, 1, ...newSpans);
      usedAnchors.add(norm(anchor));
      usedHosts.add(host);
      linksAdded++;
      injected = true;
      break;
    }
  }
}

// --- 5. Patch the document with the updated body ---
if (linksAdded === 0) {
  return [{ json: { docId, externalLinksAdded: 0, message: 'AI found no insertable authoritative anchors', picks } }];
}
const mutations = { mutations: [{ patch: { id: docId, set: { body } } }] };
const patchRes = await sanity('POST', `data/mutate/${DATASET}?returnIds=true`, mutations);
return [{ json: { docId, externalLinksAdded: linksAdded, links: picks.slice(0, linksAdded), sanityResult: patchRes } }];

const triggerData = $('Execute Workflow Trigger').first().json;
let schemaData = {};
try {
  schemaData = $('Schema Sanity').first().json;
} catch (e) {
  // Ignore or log
}

return [{
  json: {
    clientName: triggerData.clientName || "Supermat Client",
    telegramChatId: triggerData.telegramChatId || "",
    draftEditUrl: schemaData.draftEditUrl || "",
    keyword: triggerData.article?.primaryKeyword || "Keyword",
    title: triggerData.article?.title || "Artikel Baru",
    status: "success"
  }
}];
